# Skeptic: only packet-taught patterns; explicit I/O contract
def assess(record: dict) -> str:
    required = {'valid_fixture', 'extra_policy', 'case_id', 'json_schema', 'business_rule'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    if record.get('extra_policy') not in (None, False, 0, "", set(), [], {}):
        return 'PASS'
    return 'REJECT_SCHEMA'

valid = {"case_id": 'CASO-SYN-1A', 'extra_policy': True, 'json_schema': True, 'valid_fixture': True, 'business_rule': True}
adverse = {"case_id": 'CASO-SYN-1A-ADV', 'extra_policy': False, 'json_schema': False, 'valid_fixture': False, 'business_rule': False}
missing = {k: valid[k] for k in valid if k != 'business_rule'}
print(assess(valid))
print(assess(adverse))
print(assess(missing))

